namespace Exam.Core; public static class ListTools{public static int DiscountBySales(decimal a)=>a switch{<10000m=>0,<50000m=>5,<150000m=>10,<500000m=>20,_=>25};public static decimal RequiredPurchaseCost(double stock,double min,double pack,decimal cost){var need=Math.Max(0,min-stock);return need<=0?0:(decimal)Math.Ceiling(need/Math.Max(1,pack))*cost;}public static IEnumerable<T> Page<T>(IEnumerable<T> x,int p,int s)=>x.Skip(Math.Max(0,p-1)*s).Take(s);}
